@using Microsoft.AspNetCore.Components.Authorization

@inject NavigationManager Navigation

@code {
    [CascadingParameter]
    private Task<AuthenticationState>? AuthState { get; set; }

    protected override async Task OnInitializedAsync()
    {
        if (AuthState is not null)
        {
            var state = await AuthState;
            if (state.User.Identity?.IsAuthenticated != true)
            {
                var returnUrl = Uri.EscapeDataString(
                    new Uri(Navigation.Uri).PathAndQuery);
                Navigation.NavigateTo($"Account/Login?returnUrl={returnUrl}", forceLoad: true);
            }
        }
    }
}

@page "/Account/Login"
@using Microsoft.AspNetCore.Identity
@using sv_50d00e4392a04d26a5d25e4ec273c694.Data
@layout MainLayout

@inject SignInManager<ApplicationUser> SignInManager
@inject NavigationManager Navigation

<PageTitle>Login</PageTitle>

<div class="row justify-content-center mt-5">
    <div class="col-md-4">
        <h2>Login</h2>
        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }
        <form method="post" @formname="login">
            <AntiforgeryToken />
            <div class="mb-3">
                <label for="email" class="form-label">Email</label>
                <InputText id="email" @bind-Value="Input.Email" class="form-control" />
            </div>
            <div class="mb-3">
                <label for="password" class="form-label">Password</label>
                <InputText id="password" @bind-Value="Input.Password" type="password" class="form-control" />
            </div>
            <button type="submit" class="btn btn-primary w-100">Log in</button>
        </form>
    </div>
</div>

@code {
    private string? errorMessage;

    [SupplyParameterFromForm]
    private LoginModel Input { get; set; } = new();

    [SupplyParameterFromQuery]
    private string? ReturnUrl { get; set; }

    protected override async Task OnInitializedAsync()
    {
        if (Input.Email is not null && Input.Password is not null)
        {
            await HandleLogin();
        }
    }

    private async Task HandleLogin()
    {
        var user = await SignInManager.UserManager.FindByEmailAsync(Input.Email!);
        if (user is null)
        {
            errorMessage = "Invalid email or password.";
            return;
        }

        var result = await SignInManager.PasswordSignInAsync(
            user, Input.Password!, isPersistent: false, lockoutOnFailure: false);

        if (result.Succeeded)
        {
            Navigation.NavigateTo(ReturnUrl ?? "/", forceLoad: true);
        }
        else
        {
            errorMessage = "Invalid email or password.";
        }
    }

    private sealed class LoginModel
    {
        public string? Email { get; set; }
        public string? Password { get; set; }
    }
}

@page "/Account/Logout"
