    }
}

@page "/admin/users"
@attribute [Authorize(Roles = "Admin")]
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Identity
@using sv_50d00e4392a04d26a5d25e4ec273c694.Data

@inject UserManager<ApplicationUser> UserManager

<PageTitle>User Management</PageTitle>

<h1>User Management</h1>
<p>Manage all registered users and their roles.</p>

@if (userList is null)
{
    <p><em>Loading users...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Email</th>
                <th>Username</th>
                <th>Roles</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var entry in userList)
            {
                <tr>
                    <td>@entry.User.Email</td>
                    <td>@entry.User.UserName</td>
                    <td>@string.Join(", ", entry.Roles)</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<UserWithRoles>? userList;

    protected override async Task OnInitializedAsync()
    {
        var users = UserManager.Users.ToList();
        userList = new List<UserWithRoles>();
        foreach (var user in users)
        {
            var roles = await UserManager.GetRolesAsync(user);
            userList.Add(new UserWithRoles(user, roles));
        }
    }

    private record UserWithRoles(ApplicationUser User, IList<string> Roles);
}

